/**
 * Uses Anthropic Claude as an LLM judge to classify a PR's semver severity
 * based on build output changes: major (breaking), minor (new features), or
 * patch (bug fixes, docs, refactors with no build output change).
 *
 * Uses the same build-and-diff process as the "Generated file diff" automation:
 * both base and PR branches are built, and the build output is compared using
 * diff-directories.js.
 *
 * Expects env vars:
 *   ANTHROPIC_API_KEY - Anthropic API key
 *   ANTHROPIC_MODEL   - Optional; defaults to shared CI model in anthropic-config.mjs
 *   BUILD_DIFF        - Build output diff from diff-directories.js (may be empty)
 *   SOURCE_DIFF       - Git diff of source changes between base and PR (may be empty)
 *   PR_TITLE          - Pull request title
 *   PR_BODY           - Pull request body/description
 *   PR_FILES          - Newline-separated list of changed source file paths
 *
 * Outputs to stdout a JSON object: { "severity": "major"|"minor"|"patch", "reasoning": "..." }
 */

import { fileURLToPath } from 'node:url';

import { resolveAnthropicModel } from './anthropic-config.mjs';

const ANTHROPIC_API_URL = 'https://api.anthropic.com/v1/messages';
const MAX_BUILD_DIFF_CHARS = 80_000;
const MAX_SOURCE_DIFF_CHARS = 80_000;

const SYSTEM_PROMPT = `You are a semver classification expert for the duckduckgo/content-scope-scripts repository.

This is an npm workspace monorepo that ships privacy features and special pages to DuckDuckGo's native apps (macOS, Windows, iOS, Android). Downstream consumers integrate via npm, Swift Package Manager, and git submodules.

## Input format

You receive a **build output diff** comparing built artifacts between the base branch and the PR branch. The diff is generated by building both branches and comparing the \`build/\` directory output. It uses HTML \`<details>\` sections grouped by category:
- "Removed Files" — built artifacts only in the base build (the PR removes them)
- "New Files" — built artifacts only in the PR build (the PR adds them)
- Named groups (e.g. "Apple", "Windows", "Integration") — artifacts that exist in both but whose content differs

When the build output diff is empty, built artifacts are identical between base and PR. Do not infer semver impact from that alone — use the **source diff** and changed file list to classify the PR.

You also receive a **source diff** (unified git diff between base and PR) and the list of changed **source files**, plus the PR title/description for context. Use the source diff to inspect API, schema, feature-bundle, and messaging contract changes even when build output is unchanged.

## Public API surfaces (changes here are semver-sensitive):

1. **messaging/ package** (@duckduckgo/messaging) — Messaging, MessagingContext, MessagingTransport, platform configs (Webkit/Windows/Android), schema types, createTypedMessages, and subpath exports (lib/shared-types, lib/test-utils.mjs, lib/webkit.js, etc.)
2. **Build artifact paths** — build/<platform>/contentScope.js, Sources/ContentScopeScripts/dist/*.js, dist/pages/<name>/ — native apps reference these exact paths
3. **Feature config contracts** — LoadArgs shape, feature init/load signatures in content-scope-features.js
4. **Generated types from JSON schemas** — message types consumed by special-pages and injected features
5. **Entry points** — injected/entry-points/*.js files and their export shapes
6. **Platform feature bundles** — \`platformSupport\` in features.js maps feature names to platform builds (apple, apple-isolated, android, windows, chrome-mv3, firefox, etc.). Native apps expect specific features in specific bundles and execution contexts (page world vs isolated world). Adding or removing a feature from a platform entry changes what the native app receives.

## Classification rules:

**MAJOR** (breaking change) — assign when ANY of these apply:
- Build artifacts removed that native apps reference (files listed under "Removed Files") — but NOT removal of subresources within special-pages (e.g. images, fonts, sub-chunks)
- Removed or renamed exports from messaging/
- Changed method signatures, constructor parameters, or return types in public messaging classes
- Removed or renamed build artifact files that native apps reference
- Removed, renamed, or changed the shape of LoadArgs or feature init/load contracts
- Removed or renamed JSON schema message types
- Deleted or moved entry point files
- Removed features from any \`platformSupport\` entry in features.js — native apps have corresponding code for each bundled feature and removing one is a breaking change
- Moved features between execution contexts / content script worlds (e.g. \`apple\` → \`apple-isolated\`) — native apps may only load one world's script, so a feature moving worlds can disappear from the app's perspective
- Changed init/load behaviour in content-scope-features.js that introduces new cross-world runtime requirements (e.g. message bridges, event forwarding) that native apps must support
- Existing message schema shapes changed in backward-incompatible ways (fields added/removed/renamed, required fields changed) — this changes the native API contract
- Any change that would cause a downstream consumer's existing code to fail without modification

**MINOR** (new feature / non-breaking enhancement) — assign when ANY of these apply:
- New build artifacts added (files listed under "New Files")
- Build artifacts changed AND source files show new features, special pages, or entry points added
- Source files show new exports, classes, or methods added without removing existing ones
- New privacy features or significant feature enhancements visible in changed platform builds
- New message schema file added under \`injected/src/messages/\` (e.g. \`*.notify.json\`, \`*.request.json\`, \`*.subscribe.json\`) — these define new native-facing messaging APIs even though they compile into existing build artifacts
- New feature file added under \`injected/src/features/\`
- New entry added to \`platformSupport\` or \`platformSpecificFeatures\` in source files
- New feature-level config gate (e.g. a new \`*Enabled\` setting that gates behavior) added to an existing feature

**PATCH** (bug fix / internal) — assign when ALL of these apply:
- No build artifacts added or removed
- Build artifact changes are limited to content modifications of existing files
- Source files show only bug fixes, refactors, docs, tests, CI/tooling, or dependency updates
- No new message schema files added under \`injected/src/messages/\`
- No changes to message schema shapes (field additions/removals/renames in \`.notify.json\`, \`.request.json\`, \`.subscribe.json\` files)
- No new entries in \`platformSupport\` or \`platformSpecificFeatures\`
- OR source changes are limited to docs, tests, CI/tooling, or dependency updates with no semver-sensitive API changes (even when build output is unchanged)

Always respond with valid JSON: { "severity": "major"|"minor"|"patch", "reasoning": "..." }
The reasoning should be 2-3 concise sentences explaining the classification.`;

function truncateDiff(diff, maxChars) {
    if (!diff) return diff;
    if (diff.length <= maxChars) return diff;
    return diff.slice(0, maxChars) + '\n\n... [diff truncated] ...';
}

function formatBuildDiffSection(buildDiff) {
    if (!buildDiff.trim()) {
        return '(no build output artifacts changed — built outputs are identical between base and PR)';
    }
    return truncateDiff(buildDiff, MAX_BUILD_DIFF_CHARS);
}

function formatSourceDiffSection(sourceDiff) {
    if (!sourceDiff.trim()) {
        return '(no source changes detected)';
    }
    return truncateDiff(sourceDiff, MAX_SOURCE_DIFF_CHARS);
}

function buildUserPrompt({ buildDiff, sourceDiff, title, body, files }) {
    return `Classify this PR's semver impact using both build output changes and source changes.

## PR Title
${title}

## PR Description
${body || '(no description)'}

## Changed Source Files
${files || '(not available)'}

## Build Output Diff
${formatBuildDiffSection(buildDiff)}

## Source Diff
${formatSourceDiffSection(sourceDiff)}

Respond with JSON only: { "severity": "major"|"minor"|"patch", "reasoning": "..." }`;
}

export { buildUserPrompt, formatBuildDiffSection, formatSourceDiffSection };

async function callAnthropic(systemPrompt, userPrompt, apiKey) {
    const response = await fetch(ANTHROPIC_API_URL, {
        method: 'POST',
        headers: {
            'Content-Type': 'application/json',
            'x-api-key': apiKey,
            'anthropic-version': '2023-06-01',
        },
        body: JSON.stringify({
            model: resolveAnthropicModel(),
            max_tokens: 512,
            system: systemPrompt,
            messages: [{ role: 'user', content: userPrompt }],
        }),
    });

    if (!response.ok) {
        const text = await response.text();
        throw new Error(`Anthropic API error ${response.status}: ${text}`);
    }

    const data = await response.json();
    const content = data.content?.[0]?.text;
    if (!content) {
        throw new Error('Empty response from Anthropic API');
    }
    return content;
}

function parseResponse(text) {
    const jsonMatch = text.match(/\{[\s\S]*\}/);
    if (!jsonMatch) {
        throw new Error(`Could not extract JSON from LLM response: ${text}`);
    }
    const parsed = JSON.parse(jsonMatch[0]);
    const severity = parsed.severity?.toLowerCase();
    if (!['major', 'minor', 'patch'].includes(severity)) {
        throw new Error(`Invalid severity "${parsed.severity}" in LLM response`);
    }
    return { severity, reasoning: parsed.reasoning || '' };
}

async function main() {
    const apiKey = process.env.ANTHROPIC_API_KEY;
    if (!apiKey) {
        console.error('ANTHROPIC_API_KEY is required');
        process.exit(1);
    }

    const buildDiff = process.env.BUILD_DIFF || '';
    const sourceDiff = process.env.SOURCE_DIFF || '';
    const title = process.env.PR_TITLE || '';
    const body = process.env.PR_BODY || '';
    const files = process.env.PR_FILES || '';

    const userPrompt = buildUserPrompt({ buildDiff, sourceDiff, title, body, files });
    const rawResponse = await callAnthropic(SYSTEM_PROMPT, userPrompt, apiKey);
    const result = parseResponse(rawResponse);

    console.log(JSON.stringify(result));
}

if (process.argv[1] === fileURLToPath(import.meta.url)) {
    main();
}
